use std::fmt;

trait Labelable {
    fn format_label(&self) -> String;
}

struct Person { name: String, age: u32 } 
impl Labelable for Person {
    fn format_label(&self) -> String {
        format!("Name: {}, Age: {}", self.name, self.age)
    }
}

struct Product { sku: String, weight_grams: u32 } 
impl Labelable for Product {
    fn format_label(&self) -> String {
        format!("SKU: {}, Weight: {}g", self.sku, self.weight_grams)
    }
}

fn main() {
    let person = Person { name: String::from("Alice"), age: 30 };
    let product = Product { sku: String::from("XYZ789"), weight_grams: 500 };

    println!("n--- Label Generation ---n");
    println!("Person Label: {}", person.format_label());
    println!("Product Label: {}", product.format_label());
}

use std::fmt;

trait Addable<R> {
    fn add(self, other: R) -> Self;
}

struct Point {
    x: i32,
    y: i32,
}

impl Addable<Point> for Point {
    fn add(self, other: Point) -> Self {
        Point {
            x: self.x + other.x,
            y: self.y + other.y,
        }
    }
}

fn main() {
    let p1 = Point { x: 10, y: 20 };
    let p2 = Point { x: 5, y: 15 };
    let result = p1.add(p2);
    println!("The resulting point is: ({}, {})", result.x, result.y);
}

