use std::collections::HashMap;

struct DataPoint {
    key: String,
    value: f64,
}

fn calculate_group_averages(data: Vec<DataPoint>) -> HashMap<String, f64> {
    let mut sums: HashMap<String, (f64, i32)> = HashMap::new();

    for point in data {
        let entry = sums.entry(point.key).or_insert((0.0, 0));
        entry.0 += point.value;
        entry.1 += 1;
    }

    let mut averages: HashMap<String, f64> = HashMap::new();

    for (key, (sum, count)) in sums {
        if count > 0 {
            averages.insert(key, sum / (count as f64));
        }
    }

    averages
}

